module binary_counter_4(
   input                clk,
   input                rst,

   output reg [3:0]     Q
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge dbg_halt) begin
        if(rst) Q <= 4'b0000;
        else Q <= Q + 1;
    end
endmodule
